#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 500
#define MAXN 5000000

struct Segment {
    int start;
    int end;
};

int compare(const void *a, const void *b) {
    struct Segment *s1 = (struct Segment *)a;
    struct Segment *s2 = (struct Segment *)b;
    return s1->start - s2->start;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k, p;
        scanf("%d %d %d", &n, &k, &p);
        struct Segment kParts[MAX], pParts[MAX];
        for (int i = 0; i < k; i++) {
            scanf("%d %d", &kParts[i].start, &kParts[i].end);
        }
        for (int i = 0; i < p; i++) {
            scanf("%d %d", &pParts[i].start, &pParts[i].end);
        }
        qsort(kParts, k, sizeof(struct Segment), compare);
        qsort(pParts, p, sizeof(struct Segment), compare);
        int j = 0;
        int flag = 1;
        for (int i = 0; i < k; i++) {
            while (j < p && pParts[j].start < kParts[i].start) {
                j++;
            }
            if (j == p || pParts[j].start > kParts[i].start) {
                flag = 0;
                break;
            }
            if (pParts[j].end < kParts[i].end) {
                flag = 0;
                break;
            }
            j++;
        }
