import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Segment implements Comparable<Segment> {
        int start;
        int end;

        public Segment(int start, int end) {
            this.start = start;
            this.end = end;
        }

        @Override
        public int compareTo(Segment o) {
            return Integer.compare(this.start, o.start);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int k = scanner.nextInt();
            int p = scanner.nextInt();
            Segment[] kParts = new Segment[k];
            Segment[] pParts = new Segment[p];
            for (int i = 0; i < k; i++) {
                kParts[i] = new Segment(scanner.nextInt(), scanner.nextInt());
            }
            for (int i = 0; i < p; i++) {
                pParts[i] = new Segment(scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(kParts);
            Arrays.sort(pParts);
            int j = 0;
            boolean flag = true;
            for (int i = 0; i < k; i++) {
                while (j < p && pParts[j].start < kParts[i].start) {
                    j++;
                }
                if (j == p || pParts[j].start > kParts[i].start) {
                    flag = false;
                    break;
                }
                if (pParts[j].end < kParts[i].end) {
                    flag = false;
                    break;
                }
                j++;
            }
            if (flag) {
                System.out.println("Yes");
            } else {
                System.out.println("No");
            }
        }
    }
}

